"use client";

import { motion, useReducedMotion } from "framer-motion";
import {
  ChevronLeft,
  ChevronRight,
  Filter,
  Pencil,
  Plus,
  Star,
  Trash2,
  Search,
} from "lucide-react";
import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";

import { Button } from "@/components/ui/button";
import { getSupabaseBrowserClient } from "@/lib/supabase/browser";
import { formatFreelancerRate } from "@/lib/rate-format";

type FreelancerRow = {
  id: string;
  name: string;
  email?: string | null;
  title: string;
  skills: string[];
  rate: string;
  rateType: string;
  featured: boolean;
  dbStatus: string;
};

function useReveal() {
  const reduceMotion = useReducedMotion();
  return useMemo(
    () =>
      ({
        fadeUp: {
          hidden: { opacity: 0, y: reduceMotion ? 0 : 10 },
          show: {
            opacity: 1,
            y: 0,
            transition: { duration: reduceMotion ? 0 : 0.45, ease: "easeOut" },
          },
        },
      }) as const,
    [reduceMotion],
  );
}

function InitialAvatar({ name }: { name: string }) {
  const initials = name
    .split(" ")
    .slice(0, 2)
    .map((s) => s[0])
    .join("")
    .toUpperCase();

  return (
    <div className="w-10 h-10 rounded-full overflow-hidden bg-muted flex items-center justify-center text-xs font-semibold text-foreground">
      {initials}
    </div>
  );
}

function SkillsChips({ skills }: { skills: string[] }) {
  return (
    <div className="flex flex-wrap gap-1">
      {skills.map((skill) => (
        <span
          key={skill}
          className="px-2 py-0.5 bg-primary/10 text-primary text-[10px] font-bold rounded-full"
        >
          {skill}
        </span>
      ))}
    </div>
  );
}

function StatusCell({ status }: { status: string }) {
  const isActive = status === "active";
  return (
    <div className="flex items-center gap-2">
      <span
        className={
          "w-2 h-2 rounded-full " +
          (isActive ? "bg-green-500" : "bg-muted-foreground/40")
        }
      />
      <span
        className={
          "text-xs font-medium capitalize " +
          (isActive ? "text-green-600" : "text-muted-foreground")
        }
      >
        {status}
      </span>
    </div>
  );
}

export default function FreelancersPage() {
  const v = useReveal();
  const router = useRouter();
  const [query, setQuery] = useState("");

  const [rows, setRows] = useState<FreelancerRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState<string | null>(null);

  useEffect(() => {
    let active = true;

    (async () => {
      setLoading(true);
      setLoadError(null);
      try {
        const supabase = getSupabaseBrowserClient();
        const { data, error } = await supabase
          .from("freelancers")
          .select(
            "id, full_name, title, skills, hourly_rate, hourly_rate_min, hourly_rate_max, rate_type, featured, status, created_at",
          )
          .order("created_at", { ascending: false });

        if (error) throw error;
        if (!active) return;

        const mapped: FreelancerRow[] = (data ?? []).map((r: any) => {
          return {
            id: String(r.id),
            name: String(r.full_name ?? "Unnamed"),
            email: null,
            title: String(r.title ?? "—"),
            skills: Array.isArray(r.skills) ? r.skills.map(String) : [],
            rate:
              r.hourly_rate != null ||
              r.hourly_rate_min != null ||
              r.hourly_rate_max != null
                ? formatFreelancerRate(
                    r.hourly_rate_min ?? r.hourly_rate,
                    r.rate_type,
                    r.hourly_rate_max,
                  )
                : "—",
            rateType: String(r.rate_type ?? "hourly"),
            featured: !!r.featured,
            dbStatus: String(r.status ?? "active"),
          };
        });

        setRows(mapped);
      } catch (err) {
        setLoadError(
          err instanceof Error ? err.message : "Failed to load freelancers.",
        );
      } finally {
        if (active) setLoading(false);
      }
    })();

    return () => {
      active = false;
    };
  }, []);

  const filtered = rows.filter((r) => {
    if (!query.trim()) return true;
    const q = query.toLowerCase();
    return (
      r.name.toLowerCase().includes(q) ||
      (r.email ?? "").toLowerCase().includes(q) ||
      r.title.toLowerCase().includes(q) ||
      r.skills.some((s) => s.toLowerCase().includes(q))
    );
  });

  return (
    <div className="space-y-6">
      {/* Page header row (matches screenshot: title + search + buttons) */}
      <motion.div
        variants={v.fadeUp}
        initial="hidden"
        animate="show"
        className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between"
      >
        <div className="flex items-center gap-4 flex-1">
          <h1 className="text-xl font-bold text-foreground">Freelancers</h1>
          <div className="max-w-md w-full">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground h-4 w-4" />
              <input
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-muted/60 border-none rounded-xl py-2 pl-10 pr-4 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring placeholder:text-muted-foreground"
                placeholder="Search freelancers by name, skill, or title..."
                type="text"
              />
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <Button type="button" variant="outline" className="rounded-xl">
            <Filter className="h-4 w-4 mr-2" />
            Filter
          </Button>
          <Button asChild className="rounded-xl font-semibold">
            <Link href="/admin/add-freelancer">
              <Plus className="h-4 w-4 mr-2" />
              Add Freelancer
            </Link>
          </Button>
          <div className="w-10 h-10 rounded-full bg-muted overflow-hidden ring-2 ring-background flex items-center justify-center">
            <span className="text-xs font-semibold text-foreground">A</span>
          </div>
        </div>
      </motion.div>

      {/* Table */}
      <motion.div
        variants={v.fadeUp}
        initial="hidden"
        animate="show"
        className="bg-card rounded-xl border shadow-sm overflow-auto"
      >
        {loadError ? (
          <div className="p-6 text-sm text-destructive bg-destructive/10 border-b border-destructive/20">
            {loadError}
          </div>
        ) : null}

        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-muted/50 text-muted-foreground uppercase text-[11px] font-bold tracking-wider">
              <th className="px-6 py-4">Freelancer</th>
              <th className="px-6 py-4">Title</th>
              <th className="px-6 py-4">Skills</th>
              <th className="px-6 py-4">Rate</th>
              <th className="px-6 py-4">Status</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y">
            {loading ? (
              <tr>
                <td
                  className="px-6 py-8 text-sm text-muted-foreground"
                  colSpan={6}
                >
                  Loading freelancers...
                </td>
              </tr>
            ) : filtered.length === 0 ? (
              <tr>
                <td
                  className="px-6 py-8 text-sm text-muted-foreground"
                  colSpan={6}
                >
                  No freelancers found.
                </td>
              </tr>
            ) : (
              filtered.map((row) => (
                <tr
                  key={row.id}
                  className="hover:bg-muted/30 transition-colors"
                >
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <InitialAvatar name={row.name} />
                      <div>
                        <p className="text-sm font-semibold text-foreground">
                          {row.name}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {row.email || "—"}
                        </p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-sm text-muted-foreground">
                      {row.title}
                    </span>
                  </td>
                  <td className="px-6 py-4 truncate">
                    <SkillsChips skills={row.skills} />
                  </td>
                  <td className="px-6 py-4 text-sm font-medium">{row.rate}</td>
                  <td className="px-6 py-4">
                    <StatusCell status={row.dbStatus} />
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex items-center justify-end gap-2">
                      <button
                        type="button"
                        className="p-1.5 text-muted-foreground hover:text-primary transition-colors"
                        aria-label="Edit freelancer"
                        onClick={() =>
                          router.push(`/admin/edit-freelancer?id=${row.id}`)
                        }
                      >
                        <Pencil className="h-4 w-4" />
                      </button>
                      <button
                        type="button"
                        className={
                          "p-1.5 transition-colors " +
                          (row.featured
                            ? "text-yellow-500 hover:text-yellow-600"
                            : "text-muted-foreground hover:text-yellow-500")
                        }
                        aria-label={
                          row.featured
                            ? "Unfeature freelancer"
                            : "Feature freelancer"
                        }
                        onClick={async () => {
                          const supabase = getSupabaseBrowserClient();
                          const next = !row.featured;
                          await supabase
                            .from("freelancers")
                            .update({
                              featured: next,
                              updated_at: new Date().toISOString(),
                            })
                            .eq("id", row.id);
                          setRows((prev) =>
                            prev.map((r) =>
                              r.id === row.id ? { ...r, featured: next } : r,
                            ),
                          );
                        }}
                      >
                        <Star
                          className={
                            "h-4 w-4 " + (row.featured ? "fill-yellow-500" : "")
                          }
                        />
                      </button>
                      <button
                        type="button"
                        className="p-1.5 text-muted-foreground hover:text-destructive transition-colors"
                        aria-label="Delete freelancer"
                        onClick={() =>
                          router.push(
                            `/admin/delete-freelancer?id=${row.id}&name=${encodeURIComponent(row.name)}`,
                          )
                        }
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>

        {/* Pagination */}
        <div className="px-6 py-4 bg-muted/50 border-t flex items-center justify-between">
          <p className="text-sm text-muted-foreground">
            Showing <span className="font-semibold text-foreground">1-4</span>{" "}
            of <span className="font-semibold text-foreground">128</span>{" "}
            freelancers
          </p>

          <div className="flex items-center gap-1">
            <button
              type="button"
              className="w-8 h-8 flex items-center justify-center rounded-lg border hover:bg-background transition-colors disabled:opacity-50"
              disabled
              aria-label="Previous page"
            >
              <ChevronLeft className="h-4 w-4" />
            </button>
            <button
              type="button"
              className="w-8 h-8 flex items-center justify-center rounded-lg bg-primary text-primary-foreground text-xs font-bold"
              aria-current="page"
            >
              1
            </button>
            <button
              type="button"
              className="w-8 h-8 flex items-center justify-center rounded-lg text-xs font-medium hover:bg-muted transition-colors"
            >
              2
            </button>
            <button
              type="button"
              className="w-8 h-8 flex items-center justify-center rounded-lg text-xs font-medium hover:bg-muted transition-colors"
            >
              3
            </button>
            <span className="px-1 text-muted-foreground">...</span>
            <button
              type="button"
              className="w-8 h-8 flex items-center justify-center rounded-lg text-xs font-medium hover:bg-muted transition-colors"
            >
              12
            </button>
            <button
              type="button"
              className="w-8 h-8 flex items-center justify-center rounded-lg border hover:bg-background transition-colors"
              aria-label="Next page"
            >
              <ChevronRight className="h-4 w-4" />
            </button>
          </div>
        </div>
      </motion.div>
    </div>
  );
}

"use client";

import Link from "next/link";
import Image from "next/image";
import { useRouter } from "next/navigation";
import { Eye, EyeOff, Lock, Mail } from "lucide-react";
import { useState } from "react";

import { getSupabaseBrowserClient } from "@/lib/supabase/browser";
import { isAllowedAdminEmail, normalizeEmail } from "@/lib/admin-auth";

function BrandMark() {
  return (
    <div className="bg-primary/10 p-3 rounded-xl border border-primary/20">
      <svg
        className="size-8 text-primary"
        fill="none"
        viewBox="0 0 48 48"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <path
          fill="currentColor"
          fillRule="evenodd"
          clipRule="evenodd"
          d="M24 4H6V17.3333V30.6667H24V44H42V30.6667V17.3333H24V4Z"
        />
      </svg>
    </div>
  );
}

export default function AdminLoginContent() {
  const router = useRouter();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  return (
    <div className="light relative min-h-screen flex flex-col items-center justify-center p-6 overflow-hidden bg-background text-foreground antialiased selection:bg-primary/30">
      <div className="w-full flex items-center justify-center flex-col max-w-110 z-10">
        {/* Brand */}
        <Image
          src="/logo.png"
          alt="ProAssistNG"
          width={224}
          height={149}
          className="rounded-full h-28 mb-6 w-auto"
          priority
        />

        {/* Card */}
        <div className="bg-card rounded-xl shadow-2xl border border-border/50 overflow-hidden">
          <div className="p-8">
            <div className="mb-8">
              <h2 className="text-xl font-semibold">Admin Login</h2>
              <p className="text-sm text-muted-foreground mt-1">
                Please enter your credentials to continue
              </p>
            </div>

            <form
              className="space-y-5"
              onSubmit={(e) => {
                (async () => {
                  e.preventDefault();
                  setSubmitting(true);
                  setError(null);
                  try {
                    const emailNormalized = normalizeEmail(email);
                    if (!isAllowedAdminEmail(emailNormalized)) {
                      setError(
                        `Only ${"proassistng@gmail.com"} is allowed to log in as an admin.`,
                      );
                      return;
                    }

                    const supabase = getSupabaseBrowserClient();
                    const { error } = await supabase.auth.signInWithPassword({
                      email: emailNormalized,
                      password,
                    });

                    if (error) {
                      setError(error.message);
                      return;
                    }

                    router.push("/admin");
                  } catch (err) {
                    setError(
                      err instanceof Error
                        ? err.message
                        : "Login failed. Please try again.",
                    );
                  } finally {
                    setSubmitting(false);
                  }
                })();
              }}
            >
              <div className="space-y-2">
                <label className="block text-sm font-medium">
                  Email Address
                </label>
                <div className="relative group">
                  <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-muted-foreground group-focus-within:text-primary transition-colors">
                    <Mail className="h-5 w-5" />
                  </div>
                  <input
                    value={email}
                    onChange={(e) => setEmail(e.currentTarget.value)}
                    className="block w-full pl-11 pr-4 py-3 bg-muted/30 border border-border rounded-xl text-foreground placeholder:text-muted-foreground focus:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:border-transparent transition-all text-sm"
                    placeholder="admin@proassistng.com"
                    type="email"
                    autoComplete="email"
                    required
                  />
                </div>
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center">
                  <label className="block text-sm font-medium">Password</label>
                  <Link
                    href="#"
                    prefetch={false}
                    className="text-xs font-medium text-primary hover:opacity-80 transition-opacity"
                  >
                    Forgot password?
                  </Link>
                </div>
                <div className="relative group">
                  <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none text-muted-foreground group-focus-within:text-primary transition-colors">
                    <Lock className="h-5 w-5" />
                  </div>
                  <input
                    value={password}
                    onChange={(e) => setPassword(e.currentTarget.value)}
                    className="block w-full pl-11 pr-12 py-3 bg-muted/30 border border-border rounded-xl text-foreground placeholder:text-muted-foreground focus:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:border-transparent transition-all text-sm"
                    placeholder="••••••••"
                    type={showPassword ? "text" : "password"}
                    autoComplete="current-password"
                    required
                  />
                  <button
                    type="button"
                    className="absolute inset-y-0 right-0 pr-4 flex items-center text-muted-foreground hover:text-foreground transition-colors"
                    onClick={() => setShowPassword((v) => !v)}
                    aria-label={
                      showPassword ? "Hide password" : "Show password"
                    }
                  >
                    {showPassword ? (
                      <EyeOff className="h-5 w-5" />
                    ) : (
                      <Eye className="h-5 w-5" />
                    )}
                  </button>
                </div>
              </div>

              <div className="flex items-center">
                <input
                  id="remember-me"
                  name="remember-me"
                  type="checkbox"
                  checked={rememberMe}
                  onChange={(e) => setRememberMe(e.currentTarget.checked)}
                  className="h-4 w-4 rounded border-border text-primary focus:ring-primary/20 bg-background"
                />
                <label
                  htmlFor="remember-me"
                  className="ml-2 block text-sm text-muted-foreground"
                >
                  Keep me logged in
                </label>
              </div>

              <button
                type="submit"
                disabled={submitting}
                className={
                  "w-full flex justify-center items-center py-3.5 px-4 rounded-xl bg-primary hover:opacity-90 text-primary-foreground font-semibold text-sm transition-all shadow-lg shadow-primary/20 active:scale-[0.98] disabled:opacity-60 disabled:hover:opacity-60 disabled:active:scale-100"
                }
              >
                {submitting ? "Signing in..." : "Sign In to Dashboard"}
              </button>

              {error ? (
                <div className="text-sm text-destructive bg-destructive/10 border border-destructive/20 rounded-xl p-3">
                  {error}
                </div>
              ) : null}

              <div className="text-xs text-muted-foreground">
                Need an account?{" "}
                <Link
                  href="/admin/signup"
                  className="font-medium text-primary hover:opacity-80 transition-opacity"
                >
                  Sign up
                </Link>
              </div>
            </form>
          </div>

          <div className="px-8 py-4 bg-muted/30 border-t border-border flex justify-between items-center">
            <span className="text-[11px] uppercase tracking-wider text-muted-foreground font-semibold">
              Security Level: High
            </span>
            <div className="flex gap-2 items-center">
              <div className="size-1.5 rounded-full bg-emerald-500" />
              <span className="text-[11px] text-muted-foreground">
                Systems Operational
              </span>
            </div>
          </div>
        </div>

        {/* <div className="mt-8 flex justify-center gap-6">
          <Link
            href="#"
            prefetch={false}
            className="text-xs text-muted-foreground hover:text-foreground transition-colors"
          >
            Privacy Policy
          </Link>
          <Link
            href="#"
            prefetch={false}
            className="text-xs text-muted-foreground hover:text-foreground transition-colors"
          >
            Terms of Service
          </Link>
          <Link
            href="#"
            prefetch={false}
            className="text-xs text-muted-foreground hover:text-foreground transition-colors"
          >
            Contact Support
          </Link>
        </div> */}
      </div>

      <div className="absolute bottom-0 left-0 w-full h-1 bg-linear-to-r from-transparent via-primary/20 to-transparent" />
    </div>
  );
}

"use client";

import {
  Archive,
  CheckCircle2,
  Image,
  MailOpen,
  RefreshCw,
  Send,
  Trash2,
  User,
  XCircle,
} from "lucide-react";
import { AnimatePresence, motion } from "framer-motion";
import { useSearchParams } from "next/navigation";
import { useEffect, useMemo, useState } from "react";

import { getSupabaseBrowserClient } from "@/lib/supabase/browser";

type Attachment = {
  name: string;
  size: string;
};

type Message = {
  id: string;
  name: string;
  email: string;
  subject: string;
  preview: string;
  timeLabel: string;
  receivedAtLabel: string;
  userId: string;
  signatureTitle?: string;
  unread?: boolean;
  starred?: boolean;
  status?: string;
  attachments?: Attachment[];
  body: string[];
};

type TabKey = "all" | "unread" | "starred";

function initials(name: string) {
  const parts = name.split(" ").filter(Boolean);
  return parts
    .slice(0, 2)
    .map((p) => p[0]?.toUpperCase())
    .join("");
}

export default function AdminMessagesPage() {
  const searchParams = useSearchParams();
  const query = searchParams.get("q") ?? "";
  const [activeTab, setActiveTab] = useState<TabKey>("all");
  const [messages, setMessages] = useState<Message[]>([]);
  const [selectedId, setSelectedId] = useState<string>("");
  const [readState, setReadState] = useState<Record<string, boolean>>({});
  const [loading, setLoading] = useState(false);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [fetchKey, setFetchKey] = useState(0);
  const [replyText, setReplyText] = useState("");
  const [replySending, setReplySending] = useState(false);
  const [toast, setToast] = useState<{
    type: "success" | "error";
    message: string;
  } | null>(null);

  useEffect(() => {
    if (!toast) return;
    const t = setTimeout(() => setToast(null), 4500);
    return () => clearTimeout(t);
  }, [toast]);

  useEffect(() => {
    let active = true;

    (async () => {
      setLoading(true);
      setLoadError(null);

      try {
        const supabase = getSupabaseBrowserClient();
        const { data, error } = await supabase
          .from("messages")
          .select(
            "id, sender_name, sender_email, user_ref, subject, body, attachments, starred, unread, status, received_at",
          )
          .order("received_at", { ascending: false })
          .limit(50);

        if (error) throw error;
        if (!active) return;

        const mapped: Message[] = (data ?? []).map((r: any) => {
          const receivedAt = r.received_at
            ? new Date(r.received_at)
            : new Date();
          const timeLabel = receivedAt.toLocaleTimeString(undefined, {
            hour: "2-digit",
            minute: "2-digit",
          });
          const receivedAtLabel = receivedAt.toLocaleString(undefined, {
            year: "numeric",
            month: "short",
            day: "2-digit",
            hour: "2-digit",
            minute: "2-digit",
          });
          const bodyText = String(r.body ?? "");
          const bodyParts = bodyText
            .split(/\n\s*\n/g)
            .map((p: string) => p.trim())
            .filter(Boolean);
          const preview = bodyText.replace(/\s+/g, " ").trim().slice(0, 140);
          const rawAttachments = r.attachments;
          const attachments: Attachment[] = Array.isArray(rawAttachments)
            ? rawAttachments
                .map((a: any) => ({
                  name: String(a?.name ?? "attachment"),
                  size: String(a?.size ?? ""),
                }))
                .filter((a: Attachment) => !!a.name)
            : [];

          return {
            id: String(r.id),
            name: String(r.sender_name ?? "Unknown"),
            email: String(r.sender_email ?? ""),
            subject: String(r.subject ?? "(no subject)"),
            preview: preview || "—",
            timeLabel,
            receivedAtLabel,
            userId: String(r.user_ref ?? ""),
            unread: !!r.unread,
            starred: !!r.starred,
            status: String(r.status ?? "open"),
            attachments: attachments.length ? attachments : undefined,
            body: bodyParts.length ? bodyParts : [bodyText || "—"],
          };
        });

        setMessages(mapped.length ? mapped : []);
        setSelectedId((prev) => prev || mapped[0]?.id || "");
        setReadState((prev) => {
          const next = { ...prev };
          for (const m of mapped) {
            if (next[m.id] === undefined) next[m.id] = !(m.unread ?? false);
          }
          return next;
        });
      } catch (err) {
        setLoadError(
          err instanceof Error ? err.message : "Failed to load messages.",
        );
      } finally {
        if (active) setLoading(false);
      }
    })();

    return () => {
      active = false;
    };
  }, [fetchKey]);

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return messages.filter((m) => {
      const isRead = readState[m.id] ?? true;
      const isUnread = !isRead;
      const matchesTab =
        activeTab === "all"
          ? true
          : activeTab === "unread"
            ? isUnread
            : !!m.starred;
      if (!matchesTab) return false;
      if (!q) return true;
      return (
        m.name.toLowerCase().includes(q) ||
        m.email.toLowerCase().includes(q) ||
        m.subject.toLowerCase().includes(q)
      );
    });
  }, [activeTab, query, messages, readState]);

  const selected = useMemo(
    () =>
      messages.find((m) => m.id === selectedId) ?? filtered[0] ?? messages[0],
    [selectedId, filtered, messages],
  );

  return (
    <div className="-m-4 flex min-h-[calc(100vh-4rem)] flex-col overflow-hidden bg-background sm:-m-6 lg:-m-8 lg:flex-row">
      {/* Messages list */}
      <section className="w-full border-b border-border bg-card/60 overflow-hidden lg:w-2/5 lg:min-w-88 lg:border-b-0 lg:border-r">
        <div className="sticky top-0 z-10 flex flex-wrap items-center justify-between gap-3 border-b border-border bg-background/70 p-4 backdrop-blur">
          <div className="flex gap-2">
            <button
              type="button"
              onClick={() => setActiveTab("all")}
              className={
                "px-3 py-1 text-xs font-bold rounded-full transition-colors " +
                (activeTab === "all"
                  ? "bg-primary text-primary-foreground"
                  : "text-muted-foreground hover:bg-muted")
              }
            >
              All
            </button>
            <button
              type="button"
              onClick={() => setActiveTab("unread")}
              className={
                "px-3 py-1 text-xs font-medium rounded-full transition-colors " +
                (activeTab === "unread"
                  ? "bg-primary text-primary-foreground"
                  : "text-muted-foreground hover:bg-muted")
              }
            >
              Unread
            </button>
            <button
              type="button"
              onClick={() => setActiveTab("starred")}
              className={
                "px-3 py-1 text-xs font-medium rounded-full transition-colors " +
                (activeTab === "starred"
                  ? "bg-primary text-primary-foreground"
                  : "text-muted-foreground hover:bg-muted")
              }
            >
              Starred
            </button>
          </div>
          <div className="flex items-center gap-3">
            <button
              type="button"
              className="text-primary text-xs font-bold hover:underline"
              onClick={() => {
                setReadState((prev) => {
                  const next = { ...prev };
                  for (const m of messages) next[m.id] = true;
                  return next;
                });
              }}
            >
              Mark all read
            </button>
            <button
              type="button"
              aria-label="Refresh"
              title="Refresh"
              onClick={() => setFetchKey((k) => k + 1)}
              disabled={loading}
              className="p-1.5 rounded-lg text-muted-foreground hover:text-primary hover:bg-muted transition-colors disabled:opacity-40"
            >
              <RefreshCw
                className={`w-3.5 h-3.5 transition-transform ${loading ? "animate-spin" : ""}`}
              />
            </button>
          </div>
        </div>

        <div className="max-h-[42vh] overflow-y-auto divide-y divide-border lg:max-h-none lg:h-full">
          {loadError ? (
            <div className="p-6 text-sm text-destructive bg-destructive/10 border-b border-destructive/20">
              {loadError}
            </div>
          ) : null}
          {loading ? (
            <div className="p-6 text-sm text-muted-foreground">
              Loading messages...
            </div>
          ) : null}
          {filtered.map((m) => {
            const isSelected = selected?.id === m.id;
            const isRead = readState[m.id] ?? true;
            const isUnread = !isRead;

            return (
              <button
                key={m.id}
                type="button"
                onClick={() => {
                  setSelectedId(m.id);
                  setReadState((prev) => ({ ...prev, [m.id]: true }));
                }}
                className={
                  "w-full p-3 text-left transition-colors sm:p-4 " +
                  (isSelected
                    ? "bg-primary/5 border-l-4 border-primary"
                    : "hover:bg-muted/40")
                }
              >
                <div className="flex justify-between items-start mb-1">
                  <div className="flex items-center gap-2 min-w-0">
                    <h3 className="font-bold text-sm text-foreground truncate">
                      {m.name}
                    </h3>
                    {isUnread ? (
                      <span className="w-1.5 h-1.5 bg-primary rounded-full" />
                    ) : null}
                  </div>
                  <span className="text-[10px] font-medium text-muted-foreground whitespace-nowrap">
                    {m.timeLabel}
                  </span>
                </div>
                <p className="text-xs text-muted-foreground mb-1 truncate font-medium">
                  {m.email}
                </p>
                <h4
                  className={
                    "text-sm mb-1 truncate " +
                    (isSelected
                      ? "font-semibold text-primary italic"
                      : "font-medium text-foreground")
                  }
                >
                  {m.subject}
                </h4>
                <p className="text-xs text-muted-foreground line-clamp-2 leading-relaxed">
                  {m.preview}
                </p>
              </button>
            );
          })}

          {!loading && filtered.length === 0 ? (
            <div className="p-8 text-sm text-muted-foreground">
              No messages found.
            </div>
          ) : null}
        </div>
      </section>

      {/* Detail panel */}
      <section className="flex w-full min-h-0 flex-col overflow-hidden bg-background lg:w-3/5">
        {/* Actions bar */}
        <div className="shrink-0 border-b border-border bg-background px-4 py-3 sm:px-6 lg:px-8">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div className="flex flex-wrap items-center gap-2 sm:gap-3">
              <button
                type="button"
                title="Archive"
                disabled={!selected}
                className="p-2 text-muted-foreground hover:bg-muted hover:text-foreground rounded-lg transition-colors disabled:opacity-40"
                onClick={async () => {
                  if (!selected) return;
                  const supabase = getSupabaseBrowserClient();
                  await supabase
                    .from("messages")
                    .update({ status: "archived" })
                    .eq("id", selected.id);
                  setMessages((prev) =>
                    prev.filter((m) => m.id !== selected.id),
                  );
                  const next = filtered.find((m) => m.id !== selected.id);
                  setSelectedId(next?.id ?? "");
                  setToast({ type: "success", message: "Message archived." });
                }}
              >
                <Archive className="w-4 h-4" />
              </button>
              <button
                type="button"
                title="Delete"
                disabled={!selected}
                className="p-2 text-muted-foreground hover:bg-destructive/10 hover:text-destructive rounded-lg transition-colors disabled:opacity-40"
                onClick={async () => {
                  if (!selected) return;
                  const supabase = getSupabaseBrowserClient();
                  await supabase
                    .from("messages")
                    .delete()
                    .eq("id", selected.id);
                  setMessages((prev) =>
                    prev.filter((m) => m.id !== selected.id),
                  );
                  const next = filtered.find((m) => m.id !== selected.id);
                  setSelectedId(next?.id ?? "");
                  setToast({ type: "success", message: "Message deleted." });
                }}
              >
                <Trash2 className="w-4 h-4" />
              </button>
              <div className="mx-1 h-6 w-px bg-border sm:mx-2" />
              <button
                type="button"
                title="Mark as unread"
                disabled={!selected}
                className="p-2 text-muted-foreground hover:bg-muted rounded-lg transition-colors disabled:opacity-40"
                onClick={async () => {
                  if (!selected) return;
                  setReadState((prev) => ({ ...prev, [selected.id]: false }));
                  const supabase = getSupabaseBrowserClient();
                  await supabase
                    .from("messages")
                    .update({ unread: true })
                    .eq("id", selected.id);
                }}
              >
                <MailOpen className="w-4 h-4" />
              </button>
            </div>

            <button
              type="button"
              disabled={!selected}
              title={
                selected?.status === "resolved"
                  ? "Mark as Open"
                  : "Mark as Resolved"
              }
              className={`inline-flex items-center gap-2 rounded-xl px-3 py-2 text-xs font-bold transition-colors disabled:opacity-40 sm:px-4 sm:text-sm ${
                selected?.status === "resolved"
                  ? "bg-muted text-muted-foreground hover:bg-muted/70"
                  : "bg-primary/10 text-primary hover:bg-primary/15"
              }`}
              onClick={async () => {
                if (!selected) return;
                const newStatus =
                  selected.status === "resolved" ? "open" : "resolved";
                const supabase = getSupabaseBrowserClient();
                await supabase
                  .from("messages")
                  .update({ status: newStatus })
                  .eq("id", selected.id);
                setMessages((prev) =>
                  prev.map((m) =>
                    m.id === selected.id ? { ...m, status: newStatus } : m,
                  ),
                );
                setToast({
                  type: "success",
                  message:
                    newStatus === "resolved"
                      ? "Marked as resolved."
                      : "Marked as open.",
                });
              }}
            >
              <CheckCircle2 className="w-4 h-4" />
              {selected?.status === "resolved"
                ? "Mark as Open"
                : "Mark as Resolved"}
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-4 sm:p-6 lg:p-8">
          {selected ? (
            <div className="max-w-3xl mx-auto">
              <div className="mb-6 flex flex-col items-start justify-between gap-3 sm:mb-8 sm:flex-row sm:items-start sm:gap-6">
                <div className="flex min-w-0 items-center gap-3 sm:gap-4">
                  <div className="h-12 w-12 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold text-xl shrink-0">
                    {initials(selected.name) || "U"}
                  </div>
                  <div className="min-w-0">
                    <h2 className="truncate text-lg font-bold text-foreground sm:text-xl">
                      {selected.name}
                    </h2>
                    <p className="text-sm text-muted-foreground truncate">
                      {selected.email} • User ID: {selected.userId}
                    </p>
                  </div>
                </div>
                <div className="shrink-0 text-left sm:text-right">
                  <p className="text-xs font-bold text-muted-foreground">
                    RECEIVED
                  </p>
                  <p className="text-sm font-medium text-foreground/80">
                    {selected.receivedAtLabel}
                  </p>
                </div>
              </div>

              <div className="rounded-2xl border border-border bg-card p-4 shadow-sm sm:p-6">
                <h1 className="mb-4 border-b border-border pb-4 text-base font-bold text-foreground sm:text-lg">
                  Subject: {selected.subject}
                </h1>
                <div className="prose prose-slate dark:prose-invert max-w-none space-y-4">
                  {selected.body.map((p, idx) => (
                    <p key={idx} className="text-foreground/80 leading-relaxed">
                      {p}
                    </p>
                  ))}

                  {selected.attachments?.length ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 py-4">
                      {selected.attachments.map((a) => (
                        <div
                          key={a.name}
                          className="border border-border rounded-xl p-3 flex items-center gap-3 bg-muted/30"
                        >
                          <Image className="w-4 h-4 text-primary" />
                          <div className="flex-1 overflow-hidden">
                            <p className="text-xs font-bold truncate">
                              {a.name}
                            </p>
                            <p className="text-[10px] text-muted-foreground">
                              {a.size}
                            </p>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : null}

                  <p className="text-foreground/80 leading-relaxed pt-4">
                    Best regards,
                    <br />
                    <strong>{selected.name}</strong>
                    {selected.signatureTitle ? (
                      <>
                        <br />
                        {selected.signatureTitle}
                      </>
                    ) : null}
                  </p>
                </div>
              </div>

              <div className="mt-6 flex flex-col gap-3 sm:mt-8 sm:flex-row sm:gap-4">
                <div className="hidden h-10 w-10 shrink-0 items-center justify-center rounded-full bg-muted sm:flex">
                  <User className="w-5 h-5 text-muted-foreground" />
                </div>
                <div className="flex-1">
                  {selected.email ? (
                    <p className="text-xs text-muted-foreground mb-2">
                      Reply will be sent to{" "}
                      <span className="font-semibold text-foreground">
                        {selected.email}
                      </span>
                    </p>
                  ) : (
                    <p className="text-xs text-amber-500 mb-2 font-medium">
                      ⚠ No email address on this message — reply cannot be
                      delivered.
                    </p>
                  )}
                  <textarea
                    value={replyText}
                    onChange={(e) => setReplyText(e.target.value)}
                    className="w-full bg-background border border-border rounded-2xl p-4 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring min-h-30 resize-none"
                    placeholder={
                      selected.email
                        ? `Type your reply to ${selected.name}…`
                        : "No email address available."
                    }
                    disabled={!selected.email || replySending}
                  />
                  <div className="mt-2 flex justify-end">
                    <button
                      type="button"
                      disabled={
                        !selected.email || !replyText.trim() || replySending
                      }
                      className="inline-flex w-full items-center justify-center gap-2 rounded-xl bg-primary px-6 py-2 text-xs font-bold text-primary-foreground transition-colors hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50 sm:w-auto"
                      onClick={async () => {
                        if (!selected.email || !replyText.trim()) return;
                        setReplySending(true);
                        try {
                          const supabase = getSupabaseBrowserClient();
                          const {
                            data: { session },
                          } = await supabase.auth.getSession();

                          const res = await fetch("/api/send-reply", {
                            method: "POST",
                            headers: {
                              "Content-Type": "application/json",
                              ...(session?.access_token
                                ? {
                                    Authorization: `Bearer ${session.access_token}`,
                                  }
                                : {}),
                            },
                            body: JSON.stringify({
                              to: selected.email,
                              toName: selected.name,
                              subject: selected.subject,
                              replyBody: replyText.trim(),
                            }),
                          });
                          const json = await res.json();
                          if (!res.ok)
                            throw new Error(json.error ?? "Failed to send.");
                          setToast({
                            type: "success",
                            message: `Reply sent to ${selected.email}`,
                          });
                          setReplyText("");
                        } catch (err) {
                          setToast({
                            type: "error",
                            message:
                              err instanceof Error
                                ? err.message
                                : "Failed to send reply.",
                          });
                        } finally {
                          setReplySending(false);
                        }
                      }}
                    >
                      <Send className="w-3.5 h-3.5" />
                      {replySending ? "Sending…" : "Send Reply"}
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="max-w-3xl mx-auto text-sm text-muted-foreground">
              Select a message.
            </div>
          )}
        </div>
      </section>

      {/* TOAST */}
      <AnimatePresence>
        {toast && (
          <motion.div
            key="reply-toast"
            initial={{ opacity: 0, y: 24, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 12, scale: 0.95 }}
            transition={{ duration: 0.25, ease: "easeOut" }}
            className={`fixed bottom-4 left-4 right-4 z-50 flex max-w-sm items-center gap-3 rounded-2xl px-5 py-4 text-sm font-medium shadow-xl sm:bottom-6 sm:left-auto sm:right-6 ${
              toast.type === "success"
                ? "bg-green-600 text-white"
                : "bg-red-600 text-white"
            }`}
          >
            {toast.type === "success" ? (
              <CheckCircle2 className="h-5 w-5 shrink-0" />
            ) : (
              <XCircle className="h-5 w-5 shrink-0" />
            )}
            <span>{toast.message}</span>
            <button
              onClick={() => setToast(null)}
              className="ml-2 opacity-70 hover:opacity-100 transition-opacity"
              aria-label="Dismiss"
            >
              ×
            </button>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

"use client";

import { motion, useReducedMotion } from "framer-motion";
import {
  Briefcase,
  MessageSquare,
  MoreHorizontal,
  Star,
  TrendingDown,
  TrendingUp,
  Users,
} from "lucide-react";
import { useEffect, useMemo, useState } from "react";

import { getSupabaseBrowserClient } from "@/lib/supabase/browser";
import { formatFreelancerRate } from "@/lib/rate-format";

const ADMIN_TOAST_KEY = "proassist_admin_toast";

type Trend = { value: string; direction: "up" | "down" };

type StatKey =
  | "totalFreelancers"
  | "featuredFreelancers"
  | "newMessages"
  | "activeProjects";

type DashboardStats = Record<StatKey, { value: number; trend: Trend }>;

type RecentFreelancer = {
  name: string;
  role: string;
  rate: string;
  status: "Active" | "Pending" | "Idle";
};

type ActivityItem = {
  title: string;
  detail: string;
  time: string;
  highlight: boolean;
  timestamp: number;
};

function isMissingColumnOrBadRequest(err: unknown): boolean {
  if (!err || typeof err !== "object") return false;
  const anyErr = err as { code?: unknown; message?: unknown };
  const message = typeof anyErr.message === "string" ? anyErr.message : "";
  // PostgREST often uses 400s for unknown columns (select/order).
  return (
    anyErr.code === "PGRST204" ||
    message.toLowerCase().includes("column") ||
    message.toLowerCase().includes("created_at")
  );
}

function isNotFoundOrNoExposure(err: unknown): boolean {
  if (!err || typeof err !== "object") return false;
  const anyErr = err as { code?: unknown; message?: unknown };
  const message = typeof anyErr.message === "string" ? anyErr.message : "";
  return (
    anyErr.code === "42P01" ||
    message.toLowerCase().includes("not found") ||
    message.toLowerCase().includes("does not exist")
  );
}

function formatTrend(current: number, previous: number): Trend {
  if (previous <= 0) {
    return { value: "+0.0%", direction: "up" };
  }
  const delta = ((current - previous) / previous) * 100;
  const direction: Trend["direction"] = delta >= 0 ? "up" : "down";
  const sign = delta >= 0 ? "+" : "";
  return { value: `${sign}${delta.toFixed(1)}%`, direction };
}

function timeAgo(date: Date): string {
  const seconds = Math.max(1, Math.floor((Date.now() - date.getTime()) / 1000));
  const minutes = Math.floor(seconds / 60);
  const hours = Math.floor(minutes / 60);
  const days = Math.floor(hours / 24);
  if (minutes < 1) return `${seconds} sec ago`;
  if (hours < 1) return `${minutes} mins ago`;
  if (days < 1) return `${hours} hours ago`;
  return `${days} days ago`;
}

function useReveal() {
  const reduceMotion = useReducedMotion();

  return useMemo(
    () =>
      ({
        card: {
          hidden: { opacity: 0, y: reduceMotion ? 0 : 10 },
          show: {
            opacity: 1,
            y: 0,
            transition: { duration: reduceMotion ? 0 : 0.45, ease: "easeOut" },
          },
        },
        stagger: {
          hidden: {},
          show: {
            transition: {
              staggerChildren: reduceMotion ? 0 : 0.06,
              delayChildren: reduceMotion ? 0 : 0.02,
            },
          },
        },
      }) as const,
    [reduceMotion],
  );
}

function StatCard({
  title,
  value,
  Icon,
  trend,
}: {
  title: string;
  value: string;
  Icon: React.ComponentType<{ className?: string }>;
  trend: Trend;
}) {
  const TrendIcon = trend.direction === "up" ? TrendingUp : TrendingDown;
  const trendColor =
    trend.direction === "up" ? "text-primary" : "text-destructive";

  return (
    <div className="bg-card p-6 rounded-xl border shadow-sm hover:shadow-md transition-shadow">
      <div className="flex justify-between items-start mb-4">
        <div className="p-2 bg-muted rounded-lg text-muted-foreground">
          <Icon className="w-5 h-5" />
        </div>
        <span
          className={
            "text-xs font-medium flex items-center gap-1 " + trendColor
          }
        >
          {trend.value} <TrendIcon className="w-3 h-3" />
        </span>
      </div>
      <h3 className="text-muted-foreground text-sm font-medium">{title}</h3>
      <p className="text-2xl font-bold text-foreground mt-1">{value}</p>
    </div>
  );
}

function StatusPill({ status }: { status: "Active" | "Pending" | "Idle" }) {
  const styles =
    status === "Active"
      ? "bg-primary/15 text-primary"
      : status === "Pending"
        ? "bg-amber-500/15 text-amber-700"
        : "bg-muted text-muted-foreground";

  return (
    <span
      className={
        "inline-flex items-center px-2 py-0.5 rounded text-xs font-medium " +
        styles
      }
    >
      {status}
    </span>
  );
}

export default function AdminPage() {
  const v = useReveal();

  const [toast, setToast] = useState<null | {
    title: string;
    message?: string;
  }>(null);

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [stats, setStats] = useState<DashboardStats>({
    totalFreelancers: { value: 0, trend: { value: "+0.0%", direction: "up" } },
    featuredFreelancers: {
      value: 0,
      trend: { value: "+0.0%", direction: "up" },
    },
    newMessages: { value: 0, trend: { value: "+0.0%", direction: "up" } },
    activeProjects: { value: 0, trend: { value: "+0.0%", direction: "up" } },
  });
  const [recentFreelancers, setRecentFreelancers] = useState<
    RecentFreelancer[]
  >([]);
  const [activity, setActivity] = useState<ActivityItem[]>([]);

  useEffect(() => {
    try {
      const raw = sessionStorage.getItem(ADMIN_TOAST_KEY);
      if (!raw) return;
      sessionStorage.removeItem(ADMIN_TOAST_KEY);

      const parsed = JSON.parse(raw) as { title?: unknown; message?: unknown };
      const next = {
        title: typeof parsed.title === "string" ? parsed.title : "Success",
        message:
          typeof parsed.message === "string" ? parsed.message : undefined,
      };
      setToast(next);

      const t = window.setTimeout(() => setToast(null), 3200);
      return () => window.clearTimeout(t);
    } catch {
      // ignore
    }
  }, []);

  useEffect(() => {
    let active = true;

    (async () => {
      setLoading(true);
      setError(null);

      try {
        const supabase = getSupabaseBrowserClient();
        const now = new Date();
        const startCurrent = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        const startPrev = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);

        const [totalFreelancers, featuredFreelancers, unreadMessages] =
          await Promise.all([
            supabase
              .from("freelancers")
              .select("id", { count: "exact", head: true }),
            supabase
              .from("freelancers")
              .select("id", { count: "exact", head: true })
              .eq("featured", true),
            supabase
              .from("messages")
              .select("id", { count: "exact", head: true })
              .eq("unread", true),
          ]);

        // Trend queries depend on timestamp columns that may not exist yet.
        const [
          totalFreelancersCurrent,
          totalFreelancersPrev,
          featuredCurrent,
          featuredPrev,
          messagesCurrent,
          messagesPrev,
        ] = await Promise.all([
          supabase
            .from("freelancers")
            .select("id", { count: "exact", head: true })
            .gte("created_at", startCurrent.toISOString()),
          supabase
            .from("freelancers")
            .select("id", { count: "exact", head: true })
            .gte("created_at", startPrev.toISOString())
            .lt("created_at", startCurrent.toISOString()),
          supabase
            .from("freelancers")
            .select("id", { count: "exact", head: true })
            .eq("featured", true)
            .gte("created_at", startCurrent.toISOString()),
          supabase
            .from("freelancers")
            .select("id", { count: "exact", head: true })
            .eq("featured", true)
            .gte("created_at", startPrev.toISOString())
            .lt("created_at", startCurrent.toISOString()),
          supabase
            .from("messages")
            .select("id", { count: "exact", head: true })
            .gte("received_at", startCurrent.toISOString()),
          supabase
            .from("messages")
            .select("id", { count: "exact", head: true })
            .gte("received_at", startPrev.toISOString())
            .lt("received_at", startCurrent.toISOString()),
        ]);

        // Optional tables for dashboard: may 404 until schema/grants are applied.
        const [activeProjects, projectsCurrent, projectsPrev, activityRows] =
          await Promise.all([
            supabase
              .from("projects")
              .select("id", { count: "exact", head: true })
              .eq("status", "active"),
            supabase
              .from("projects")
              .select("id", { count: "exact", head: true })
              .eq("status", "active")
              .gte("created_at", startCurrent.toISOString()),
            supabase
              .from("projects")
              .select("id", { count: "exact", head: true })
              .eq("status", "active")
              .gte("created_at", startPrev.toISOString())
              .lt("created_at", startCurrent.toISOString()),
            supabase
              .from("activity_events")
              .select("title, detail, highlight, created_at")
              .order("created_at", { ascending: false })
              .limit(4),
          ]);

        // Recent freelancers can fail if the table lacks created_at/status yet.
        const recentPrimary = await supabase
          .from("freelancers")
          .select(
            "full_name, title, hourly_rate, hourly_rate_min, hourly_rate_max, rate_type, status, featured",
          )
          .order("created_at", { ascending: false })
          .limit(4);

        let recentData: any[] | null = recentPrimary.data ?? null;
        let recentError: unknown = recentPrimary.error ?? null;

        if (recentError && isMissingColumnOrBadRequest(recentError)) {
          const recentFallback = await supabase
            .from("freelancers")
            .select(
              "full_name, title, hourly_rate, hourly_rate_min, hourly_rate_max, rate_type, featured",
            )
            .order("id", { ascending: false })
            .limit(4);

          recentData = recentFallback.data ?? null;
          recentError = recentFallback.error ?? null;
        }

        const firstError =
          totalFreelancers.error ||
          featuredFreelancers.error ||
          unreadMessages.error ||
          (recentError as any) ||
          null;

        if (firstError) throw firstError;

        const nextStats: DashboardStats = {
          totalFreelancers: {
            value: totalFreelancers.count ?? 0,
            trend:
              totalFreelancersCurrent.error || totalFreelancersPrev.error
                ? { value: "+0.0%", direction: "up" }
                : formatTrend(
                    totalFreelancersCurrent.count ?? 0,
                    totalFreelancersPrev.count ?? 0,
                  ),
          },
          featuredFreelancers: {
            value: featuredFreelancers.count ?? 0,
            trend:
              featuredCurrent.error || featuredPrev.error
                ? { value: "+0.0%", direction: "up" }
                : formatTrend(
                    featuredCurrent.count ?? 0,
                    featuredPrev.count ?? 0,
                  ),
          },
          newMessages: {
            value: unreadMessages.count ?? 0,
            trend:
              messagesCurrent.error || messagesPrev.error
                ? { value: "+0.0%", direction: "up" }
                : formatTrend(
                    messagesCurrent.count ?? 0,
                    messagesPrev.count ?? 0,
                  ),
          },
          activeProjects: {
            value:
              activeProjects.error &&
              isNotFoundOrNoExposure(activeProjects.error)
                ? 0
                : (activeProjects.count ?? 0),
            trend:
              projectsCurrent.error || projectsPrev.error
                ? { value: "+0.0%", direction: "up" }
                : formatTrend(
                    projectsCurrent.count ?? 0,
                    projectsPrev.count ?? 0,
                  ),
          },
        };

        const mappedRecent: RecentFreelancer[] = (recentData ?? []).map(
          (r: any) => {
            const status = String(r.status ?? "active").toLowerCase();
            const normalized: RecentFreelancer["status"] =
              status === "pending"
                ? "Pending"
                : status === "idle"
                  ? "Idle"
                  : "Active";
            return {
              name: String(r.full_name ?? "Unnamed"),
              role: String(r.title ?? "—"),
              rate:
                r.hourly_rate != null ||
                r.hourly_rate_min != null ||
                r.hourly_rate_max != null
                  ? formatFreelancerRate(
                      r.hourly_rate_min ?? r.hourly_rate,
                      r.rate_type,
                      r.hourly_rate_max,
                    )
                  : "—",
              status: normalized,
            };
          },
        );

        // Activity: prefer activity_events, otherwise derive a minimal feed from latest rows.
        let mappedActivity: ActivityItem[] = [];
        if (!activityRows.error && (activityRows.data?.length ?? 0) > 0) {
          mappedActivity = (activityRows.data ?? []).map((a: any) => {
            const ts = a.created_at ? new Date(a.created_at) : new Date();
            return {
              title: String(a.title ?? "Activity"),
              detail: String(a.detail ?? ""),
              time: timeAgo(ts),
              highlight: !!a.highlight,
              timestamp: ts.getTime(),
            };
          });
        } else {
          const [latestFreelancers, latestMessages] = await Promise.all([
            supabase
              .from("freelancers")
              .select("full_name, title, created_at")
              .order("created_at", { ascending: false })
              .limit(2),
            supabase
              .from("messages")
              .select("sender_name, subject, received_at")
              .order("received_at", { ascending: false })
              .limit(2),
          ]);

          const derived: ActivityItem[] = [];
          for (const f of latestFreelancers.data ?? []) {
            const ts = f.created_at ? new Date(f.created_at) : new Date();
            derived.push({
              title: "New freelancer registered",
              detail: `${String(f.full_name ?? "Someone")} joined as ‘${String(f.title ?? "Freelancer")}’.`,
              time: timeAgo(ts),
              highlight: true,
              timestamp: ts.getTime(),
            });
          }
          for (const m of latestMessages.data ?? []) {
            const ts = m.received_at ? new Date(m.received_at) : new Date();
            derived.push({
              title: "New message",
              detail: `${String(m.sender_name ?? "User")} sent: ‘${String(m.subject ?? "Message")}’.`,
              time: timeAgo(ts),
              highlight: false,
              timestamp: ts.getTime(),
            });
          }
          mappedActivity = derived
            .sort((a, b) => b.timestamp - a.timestamp)
            .slice(0, 4);
        }

        if (!active) return;
        setStats(nextStats);
        setRecentFreelancers(mappedRecent);
        setActivity(mappedActivity);
      } catch (err) {
        if (!active) return;
        setError(
          err instanceof Error ? err.message : "Failed to load dashboard data.",
        );
      } finally {
        if (active) setLoading(false);
      }
    })();

    return () => {
      active = false;
    };
  }, []);

  return (
    <div className="space-y-8">
      {toast ? (
        <div className="fixed top-6 right-6 z-50 max-w-90 w-[calc(100%-3rem)] sm:w-auto">
          <div className="bg-card border border-primary/25 rounded-xl p-4 shadow-sm">
            <p className="text-sm font-semibold text-foreground">
              {toast.title}
            </p>
            {toast.message ? (
              <p className="text-xs text-muted-foreground mt-1">
                {toast.message}
              </p>
            ) : null}
          </div>
        </div>
      ) : null}

      {error ? (
        <div className="bg-destructive/10 border border-destructive/20 rounded-xl p-4 text-sm text-destructive">
          {error}
        </div>
      ) : null}

      {/* STATS */}
      <motion.div
        variants={v.stagger}
        initial="hidden"
        animate="show"
        className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6"
      >
        <motion.div variants={v.card}>
          <StatCard
            title="Total Freelancers"
            value={
              loading ? "…" : stats.totalFreelancers.value.toLocaleString()
            }
            Icon={Users}
            trend={stats.totalFreelancers.trend}
          />
        </motion.div>
        <motion.div variants={v.card}>
          <StatCard
            title="Featured Freelancers"
            value={
              loading ? "…" : stats.featuredFreelancers.value.toLocaleString()
            }
            Icon={Star}
            trend={stats.featuredFreelancers.trend}
          />
        </motion.div>
        <motion.div variants={v.card}>
          <StatCard
            title="New Messages"
            value={loading ? "…" : stats.newMessages.value.toLocaleString()}
            Icon={MessageSquare}
            trend={stats.newMessages.trend}
          />
        </motion.div>
        <motion.div variants={v.card}>
          <StatCard
            title="Active Projects"
            value={loading ? "…" : stats.activeProjects.value.toLocaleString()}
            Icon={Briefcase}
            trend={stats.activeProjects.trend}
          />
        </motion.div>
      </motion.div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* RECENT FREELANCERS */}
        <div className="lg:col-span-2 bg-card rounded-xl border shadow-sm overflow-hidden">
          <div className="p-6 border-b flex items-center justify-between">
            <h3 className="font-semibold text-foreground">
              Recent Freelancers
            </h3>
            <button
              type="button"
              className="text-xs font-medium text-primary hover:underline"
            >
              View all
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-muted/50 text-[10px] uppercase tracking-wider text-muted-foreground font-bold">
                  <th className="px-6 py-4">Freelancer</th>
                  <th className="px-6 py-4">Role</th>
                  <th className="px-6 py-4">Hourly rate</th>
                  <th className="px-6 py-4">Status</th>
                  <th className="px-6 py-4" />
                </tr>
              </thead>
              <tbody className="divide-y text-sm">
                {loading ? (
                  <tr>
                    <td
                      className="px-6 py-8 text-sm text-muted-foreground"
                      colSpan={5}
                    >
                      Loading recent freelancers...
                    </td>
                  </tr>
                ) : recentFreelancers.length === 0 ? (
                  <tr>
                    <td
                      className="px-6 py-8 text-sm text-muted-foreground"
                      colSpan={5}
                    >
                      No freelancers yet.
                    </td>
                  </tr>
                ) : (
                  recentFreelancers.map((row) => (
                    <tr
                      key={row.name}
                      className="hover:bg-muted/30 transition-colors"
                    >
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-muted flex items-center justify-center text-xs font-semibold text-foreground">
                            {row.name
                              .split(" ")
                              .slice(0, 2)
                              .map((s) => s[0])
                              .join("")}
                          </div>
                          <span className="font-medium text-foreground/90">
                            {row.name}
                          </span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-muted-foreground">
                        {row.role}
                      </td>
                      <td className="px-6 py-4 font-semibold text-foreground/90">
                        {row.rate}
                      </td>
                      <td className="px-6 py-4">
                        <StatusPill status={row.status} />
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button
                          type="button"
                          className="p-1 hover:bg-muted rounded text-muted-foreground transition-colors"
                          aria-label="Row actions"
                        >
                          <MoreHorizontal className="w-4 h-4" />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>

        {/* ACTIVITY FEED */}
        <aside className="bg-card rounded-xl border shadow-sm p-6">
          <h3 className="font-semibold text-foreground mb-6">Activity Feed</h3>

          <div className="relative">
            <div className="absolute left-3 top-0 bottom-0 w-px bg-border" />
            <div className="space-y-6 relative">
              {loading ? (
                <div className="text-sm text-muted-foreground">
                  Loading activity...
                </div>
              ) : activity.length === 0 ? (
                <div className="text-sm text-muted-foreground">
                  No activity yet.
                </div>
              ) : (
                activity.map((item) => (
                  <div
                    key={item.title + item.time}
                    className="flex gap-4 items-start pl-8 relative"
                  >
                    <div
                      className={
                        "absolute left-[-1.5px] w-2 h-2 rounded-full mt-2 " +
                        (item.highlight
                          ? "bg-destructive shadow-[0_0_0_4px_rgba(0,0,0,0.06)]"
                          : "bg-muted-foreground/40")
                      }
                    />
                    <div>
                      <p className="text-xs font-bold text-foreground">
                        {item.title}
                      </p>
                      <p className="text-xs text-muted-foreground mt-1">
                        {item.detail}
                      </p>
                      <p className="text-[10px] text-muted-foreground/80 mt-1 uppercase font-semibold">
                        {item.time}
                      </p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>

          <button
            type="button"
            className="w-full mt-8 py-2 text-xs font-medium text-muted-foreground border rounded-lg hover:bg-muted/40 transition-colors"
          >
            Load more activity
          </button>
        </aside>
      </div>
    </div>
  );
}

