"use client";

import { useEffect, useState } from "react";
import { Users, RefreshCw, Trash2, Download } from "lucide-react";
import { getSupabaseBrowserClient } from "@/lib/supabase/browser";

type Subscriber = {
  id: string;
  email: string;
  subscribed_at: string;
};

export default function AdminSubscribersPage() {
  const [subscribers, setSubscribers] = useState<Subscriber[]>([]);
  const [loading, setLoading] = useState(true);
  const [fetchKey, setFetchKey] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  useEffect(() => {
    let active = true;
    setLoading(true);
    setError(null);

    (async () => {
      const supabase = getSupabaseBrowserClient();
      const { data, error } = await supabase
        .from("subscribers")
        .select("id, email, subscribed_at")
        .order("subscribed_at", { ascending: false });

      if (!active) return;
      if (error) {
        setError(error.message);
      } else {
        setSubscribers(data ?? []);
      }
      setLoading(false);
    })();

    return () => {
      active = false;
    };
  }, [fetchKey]);

  async function handleDelete(id: string) {
    setDeletingId(id);
    const supabase = getSupabaseBrowserClient();
    await supabase.from("subscribers").delete().eq("id", id);
    setSubscribers((prev) => prev.filter((s) => s.id !== id));
    setDeletingId(null);
  }

  function handleExport() {
    const csv = [
      "Email,Subscribed At",
      ...subscribers.map(
        (s) => `${s.email},${new Date(s.subscribed_at).toLocaleString()}`,
      ),
    ].join("\n");
    const blob = new Blob([csv], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "subscribers.csv";
    a.click();
    URL.revokeObjectURL(url);
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between gap-4 flex-wrap">
        <div>
          <h1 className="text-2xl font-bold">Subscribers</h1>
          <p className="text-sm text-muted-foreground mt-1">
            {loading
              ? "Loading…"
              : `${subscribers.length} subscriber${subscribers.length === 1 ? "" : "s"}`}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <button
            type="button"
            title="Refresh"
            onClick={() => setFetchKey((k) => k + 1)}
            disabled={loading}
            className="p-2 rounded-lg border text-muted-foreground hover:text-primary hover:border-primary transition-colors disabled:opacity-40"
          >
            <RefreshCw className={`w-4 h-4 ${loading ? "animate-spin" : ""}`} />
          </button>
          <button
            type="button"
            onClick={handleExport}
            disabled={loading || subscribers.length === 0}
            className="flex items-center gap-2 px-4 py-2 rounded-xl border text-sm font-semibold hover:bg-muted transition-colors disabled:opacity-40"
          >
            <Download className="w-4 h-4" />
            Export CSV
          </button>
        </div>
      </div>

      {/* Error */}
      {error && (
        <div className="rounded-xl border border-destructive/30 bg-destructive/10 px-4 py-3 text-sm text-destructive">
          {error}
        </div>
      )}

      {/* Table */}
      <div className="rounded-2xl border bg-card overflow-hidden shadow-sm">
        {loading ? (
          <div className="p-10 text-center text-sm text-muted-foreground">
            Loading subscribers…
          </div>
        ) : subscribers.length === 0 ? (
          <div className="flex flex-col items-center justify-center gap-4 py-16 text-muted-foreground">
            <Users className="w-10 h-10 opacity-30" />
            <p className="text-sm">No subscribers yet.</p>
          </div>
        ) : (
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b bg-muted/40 text-xs font-bold uppercase tracking-wider text-muted-foreground">
                <th className="px-6 py-3 text-left">#</th>
                <th className="px-6 py-3 text-left">Email</th>
                <th className="px-6 py-3 text-left">Subscribed</th>
                <th className="px-6 py-3 text-right">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {subscribers.map((s, i) => (
                <tr key={s.id} className="hover:bg-muted/30 transition-colors">
                  <td className="px-6 py-4 text-muted-foreground">{i + 1}</td>
                  <td className="px-6 py-4 font-medium">{s.email}</td>
                  <td className="px-6 py-4 text-muted-foreground whitespace-nowrap">
                    {new Date(s.subscribed_at).toLocaleDateString("en-NG", {
                      year: "numeric",
                      month: "short",
                      day: "2-digit",
                    })}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <button
                      type="button"
                      onClick={() => handleDelete(s.id)}
                      disabled={deletingId === s.id}
                      title="Remove subscriber"
                      className="p-1.5 rounded-lg text-muted-foreground hover:bg-destructive/10 hover:text-destructive transition-colors disabled:opacity-40"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

"use client";

import TalentFilters from "@/app/components/talent/TalentFilters";
import type { FiltersState } from "@/app/components/talent/TalentFilters";
import TalentSearch from "@/app/components/talent/TalentSearch";
import TalentGrid from "@/app/components/talent/TalentGrid";
import Pagination from "@/app/components/talent/Pagination";

import { useEffect, useMemo, useState } from "react";
import type { TalentCardProps } from "@/app/components/talent/TalentCard";
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion";
import { getSupabaseBrowserClient } from "@/lib/supabase/browser";
import { formatFreelancerRate } from "@/lib/rate-format";

type TalentItem = TalentCardProps & {
  category: FiltersState["category"];
  hourlyRate: number;
  experienceLevel: "Entry Level" | "Intermediate" | "Expert";
};

const PAGE_SIZE = 4;

function includesText(haystack: string, needle: string) {
  if (!needle) return true;
  return haystack.toLowerCase().includes(needle.toLowerCase());
}

function inferCategory(
  skills: string[],
  title: string,
): FiltersState["category"] {
  const text = [...skills, title].join(" ").toLowerCase();
  if (
    /react|node|python|typescript|javascript|vue|angular|laravel|php|django|mongo|postgres|mysql|aws|docker|backend|frontend|fullstack|developer|engineer/.test(
      text,
    )
  )
    return "Development";
  if (
    /figma|adobe|illustrator|photoshop|sketch|ux|ui\b|design|wireframe|prototype|invision/.test(
      text,
    )
  )
    return "Design";
  if (/writing|content|copywriting|seo|blog|editorial|copy/.test(text))
    return "Writing";
  if (
    /marketing|ads|google ads|meta ads|ppc|analytics|social media|growth|email/.test(
      text,
    )
  )
    return "Marketing";
  return "All Categories";
}

function inferExperience(
  exp: string | null,
): "Entry Level" | "Intermediate" | "Expert" {
  if (!exp) return "Intermediate";
  if (exp === "1-2 years") return "Entry Level";
  if (exp === "3-5 years") return "Intermediate";
  return "Expert";
}

export default function BrowseTalentsContent() {
  const [query, setQuery] = useState("");
  const [sort, setSort] = useState("Best Match");
  const [page, setPage] = useState(1);
  const [allTalents, setAllTalents] = useState<TalentItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState<string | null>(null);

  const [filters, setFilters] = useState<FiltersState>({
    category: "All Categories",
    minRate: "",
    maxRate: "",
    experience: { entry: true, intermediate: true, expert: true },
    ratingMin: 0,
  });

  useEffect(() => {
    let active = true;
    setLoading(true);
    setLoadError(null);

    (async () => {
      try {
        const supabase = getSupabaseBrowserClient();
        const { data, error } = await supabase
          .from("freelancers")
          .select(
            "id, full_name, title, location, experience, hourly_rate, hourly_rate_min, hourly_rate_max, rate_type, bio, skills, featured, photo_url, status",
          )
          .eq("status", "active")
          .order("featured", { ascending: false })
          .order("created_at", { ascending: false });

        if (error) throw error;
        if (!active) return;

        const mapped: TalentItem[] = (data ?? []).map((r: any) => {
          const skills: string[] = Array.isArray(r.skills)
            ? r.skills.map(String)
            : [];
          const title = String(r.title ?? "Freelancer");
          const hourlyRate =
            typeof r.hourly_rate_min === "number"
              ? r.hourly_rate_min
              : typeof r.hourly_rate === "number"
                ? r.hourly_rate
                : 0;
          return {
            id: String(r.id),
            name: String(r.full_name ?? "Freelancer"),
            role: title,
            price: formatFreelancerRate(
              r.hourly_rate_min ?? r.hourly_rate ?? null,
              r.rate_type ?? null,
              r.hourly_rate_max,
            ),
            image: r.photo_url ?? undefined,
            rating: null,
            reviews: null,
            location: String(r.location ?? "Nigeria"),
            bio: String(
              r.bio ??
                "Experienced Nigerian freelancer ready to help with your project.",
            ),
            tags: skills.slice(0, 5),
            verified: true,
            featured: !!r.featured,
            category: inferCategory(skills, title),
            hourlyRate,
            experienceLevel: inferExperience(r.experience),
          };
        });

        setAllTalents(mapped);
      } catch (err) {
        if (!active) return;
        setLoadError(
          err instanceof Error ? err.message : "Failed to load freelancers.",
        );
      } finally {
        if (active) setLoading(false);
      }
    })();

    return () => {
      active = false;
    };
  }, []);

  const filtered = useMemo(() => {
    const needle = query.trim();

    const minRate = Number(filters.minRate);
    const maxRate = Number(filters.maxRate);
    const hasMin = Number.isFinite(minRate) && filters.minRate.trim() !== "";
    const hasMax = Number.isFinite(maxRate) && filters.maxRate.trim() !== "";

    const normalizedMin = hasMin ? Math.max(0, minRate) : null;
    const normalizedMax = hasMax ? Math.max(0, maxRate) : null;

    const effectiveMin =
      normalizedMin != null && normalizedMax != null
        ? Math.min(normalizedMin, normalizedMax)
        : normalizedMin;
    const effectiveMax =
      normalizedMin != null && normalizedMax != null
        ? Math.max(normalizedMin, normalizedMax)
        : normalizedMax;

    return allTalents.filter((t) => {
      if (
        filters.category !== "All Categories" &&
        t.category !== filters.category
      ) {
        return false;
      }

      if (
        filters.ratingMin > 0 &&
        t.rating != null &&
        t.rating < filters.ratingMin
      ) {
        return false;
      }

      if (effectiveMin != null && t.hourlyRate < effectiveMin) return false;
      if (effectiveMax != null && t.hourlyRate > effectiveMax) return false;

      const expAllowed =
        (filters.experience.entry && t.experienceLevel === "Entry Level") ||
        (filters.experience.intermediate &&
          t.experienceLevel === "Intermediate") ||
        (filters.experience.expert && t.experienceLevel === "Expert");
      if (!expAllowed) return false;

      if (!needle) return true;

      const text = [t.name, t.role, t.location, t.bio, ...t.tags].join(" ");
      return includesText(text, needle);
    });
  }, [allTalents, filters, query]);

  useEffect(() => {
    setPage(1);
  }, [query, filters]);

  const sorted = useMemo(() => {
    if (sort === "Top Rated") {
      return [...filtered].sort((a, b) => (b.rating ?? 0) - (a.rating ?? 0));
    }
    if (sort === "Most Reviews") {
      return [...filtered].sort((a, b) => (b.reviews ?? 0) - (a.reviews ?? 0));
    }
    return filtered;
  }, [filtered, sort]);

  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));

  useEffect(() => {
    setPage((p) => Math.min(totalPages, Math.max(1, p)));
  }, [totalPages]);

  const pageItems = useMemo(() => {
    const start = (page - 1) * PAGE_SIZE;
    return sorted.slice(start, start + PAGE_SIZE);
  }, [page, sorted]);

  return (
    <>
      <div className="max-w-7xl mx-auto px-6 py-10">
        <div className="flex flex-col lg:flex-row gap-8">
          <TalentFilters value={filters} onChange={setFilters} />

          <div className="flex-1 space-y-6">
            <TalentSearch value={query} onChange={setQuery} />

            {loadError && (
              <p className="rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-600">
                {loadError}
              </p>
            )}

            {loading ? (
              <div className="flex items-center justify-center py-24 text-muted-foreground text-sm">
                Loading freelancers…
              </div>
            ) : (
              <TalentGrid
                talents={pageItems}
                totalFound={sorted.length}
                sort={sort}
                onSortChange={(next) => {
                  setSort(next);
                  setPage(1);
                }}
              />
            )}

            <Pagination
              page={page}
              totalPages={totalPages}
              onPageChange={setPage}
            />
          </div>
        </div>
      </div>

      <section className="max-w-7xl mx-auto px-6 pb-14">
        <div className="rounded-2xl border bg-card p-6 sm:p-8">
          <div className="mb-6">
            <h2 className="text-2xl font-bold">Frequently asked questions</h2>
            <p className="mt-2 text-muted-foreground">
              Quick answers to help you hire faster.
            </p>
          </div>

          <Accordion type="single" collapsible className="w-full">
            <AccordionItem
              value="item-1"
              className="rounded-xl border bg-background px-4"
            >
              <AccordionTrigger className="py-4 hover:no-underline">
                How do I contact a freelancer?
              </AccordionTrigger>
              <AccordionContent>
                <p className="text-muted-foreground">
                  Use the "Contact" button on a profile to start a conversation
                  and share your project details.
                </p>
              </AccordionContent>
            </AccordionItem>

            <AccordionItem
              value="item-2"
              className="mt-3 rounded-xl border bg-background px-4"
            >
              <AccordionTrigger className="py-4 hover:no-underline">
                Are freelancers on ProAssistNG vetted?
              </AccordionTrigger>
              <AccordionContent>
                <p className="text-muted-foreground">
                  Yes—profiles are reviewed for quality signals like work
                  history, skills, and client feedback.
                </p>
              </AccordionContent>
            </AccordionItem>

            <AccordionItem
              value="item-3"
              className="mt-3 rounded-xl border bg-background px-4"
            >
              <AccordionTrigger className="py-4 hover:no-underline">
                Can I filter by budget and experience?
              </AccordionTrigger>
              <AccordionContent>
                <p className="text-muted-foreground">
                  Absolutely. Use the Hourly Rate and Experience Level filters
                  to narrow down to the right fit.
                </p>
              </AccordionContent>
            </AccordionItem>

            <AccordionItem
              value="item-4"
              className="mt-3 rounded-xl border bg-background px-4"
            >
              <AccordionTrigger className="py-4 hover:no-underline">
                What happens after I hire someone?
              </AccordionTrigger>
              <AccordionContent>
                <p className="text-muted-foreground">
                  Agree on scope, timeline, and milestones, then collaborate
                  through messages and deliverables.
                </p>
              </AccordionContent>
            </AccordionItem>

            <AccordionItem
              value="item-5"
              className="mt-3 rounded-xl border bg-background px-4"
            >
              <AccordionTrigger className="py-4 hover:no-underline">
                Do you support long-term contracts?
              </AccordionTrigger>
              <AccordionContent>
                <p className="text-muted-foreground">
                  Yes—many freelancers are available for ongoing work. Use the
                  search and filters to find the right match.
                </p>
              </AccordionContent>
            </AccordionItem>
          </Accordion>
        </div>
      </section>
    </>
  );
}

"use client";

import Image from "next/image";
import { Crown, Star } from "lucide-react";
import Link from "next/link";
import { useEffect, useMemo, useRef, useState } from "react";
import { getSupabaseBrowserClient } from "@/lib/supabase/browser";
import { formatFreelancerRate } from "@/lib/rate-format";

type FreelancerCard = {
  id: string;
  name: string;
  role: string;
  price: string;
  image: string | null;
  skills: string[];
  featured: boolean;
};

function getInitials(name: string) {
  return name
    .trim()
    .split(/\s+/)
    .slice(0, 2)
    .map((p) => p[0]?.toUpperCase() ?? "")
    .join("");
}

export default function FeaturedFreelancers() {
  const [freelancers, setFreelancers] = useState<FreelancerCard[]>([]);
  const [loading, setLoading] = useState(true);
  const carouselRef = useRef<HTMLDivElement | null>(null);
  const scrollerRef = useRef<HTMLDivElement | null>(null);
  const skipNextScrollIntoViewRef = useRef(false);
  const [cardsPerPage, setCardsPerPage] = useState(1);
  const [activePage, setActivePage] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const [isInView, setIsInView] = useState(true);

  // Fetch active freelancers from Supabase
  useEffect(() => {
    (async () => {
      try {
        const supabase = getSupabaseBrowserClient();
        const { data } = await supabase
          .from("freelancers")
          .select(
            "id, full_name, title, photo_url, skills, hourly_rate, hourly_rate_min, hourly_rate_max, rate_type, featured",
          )
          .eq("status", "active")
          .order("featured", { ascending: false })
          .order("created_at", { ascending: false })
          .limit(12);

        if (data && data.length > 0) {
          setFreelancers(
            data.map((r: any) => {
              return {
                id: String(r.id),
                name: String(r.full_name ?? "Unnamed"),
                role: String(r.title ?? "Freelancer"),
                price: formatFreelancerRate(
                  r.hourly_rate_min ?? r.hourly_rate ?? null,
                  r.rate_type,
                  r.hourly_rate_max,
                ),
                image: r.photo_url ?? null,
                skills: Array.isArray(r.skills) ? r.skills.map(String) : [],
                featured: !!r.featured,
              };
            }),
          );
        }
      } catch {
        // fetch failed, freelancers stays empty
      } finally {
        setLoading(false);
      }
    })();
  }, []);
  const [availabilityByIndex, setAvailabilityByIndex] = useState<boolean[]>(
    () => freelancers.map((_, index) => index % 2 === 0),
  );

  const pageCount = useMemo(() => {
    return Math.max(1, Math.ceil(freelancers.length / cardsPerPage));
  }, [cardsPerPage]);

  useEffect(() => {
    const updateCardsPerPage = () => {
      const width = window.innerWidth;

      if (width >= 1024) return setCardsPerPage(4);
      if (width >= 768) return setCardsPerPage(2);
      return setCardsPerPage(1);
    };

    updateCardsPerPage();
    window.addEventListener("resize", updateCardsPerPage);
    return () => window.removeEventListener("resize", updateCardsPerPage);
  }, []);

  useEffect(() => {
    const el = carouselRef.current;
    if (!el) return;

    if (typeof IntersectionObserver === "undefined") return;

    const observer = new IntersectionObserver(
      (entries) => {
        const entry = entries[0];
        if (!entry) return;
        setIsInView(entry.isIntersecting);
      },
      { threshold: 0.2 },
    );

    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    if (!scrollerRef.current) return;

    // If the current active page is out of range after a resize,
    // clamp it and scroll to the clamped page.
    const clamped = Math.min(activePage, pageCount - 1);
    if (clamped !== activePage) {
      setActivePage(clamped);
      return;
    }

    if (skipNextScrollIntoViewRef.current) {
      skipNextScrollIntoViewRef.current = false;
      return;
    }

    const scroller = scrollerRef.current;
    const startIndex = clamped * cardsPerPage;
    const target = scroller.children.item(startIndex) as HTMLElement | null;
    if (!target) return;

    // Use scrollTo so autoplay only moves the carousel, not the whole page.
    scroller.scrollTo({ left: target.offsetLeft, behavior: "smooth" });
  }, [activePage, cardsPerPage, pageCount]);

  useEffect(() => {
    if (pageCount <= 1) return;
    if (isPaused) return;
    if (!isInView) return;

    const prefersReducedMotion = window.matchMedia?.(
      "(prefers-reduced-motion: reduce)",
    )?.matches;
    if (prefersReducedMotion) return;

    const id = window.setInterval(() => {
      setActivePage((p) => (p + 1) % pageCount);
    }, 3500);

    return () => window.clearInterval(id);
  }, [isPaused, pageCount, isInView]);

  useEffect(() => {
    // Lightweight "live" availability simulation.
    // If you later add a real API, replace this with fetched data.
    if (isPaused) return;
    if (!isInView) return;

    const id = window.setInterval(() => {
      if (document.visibilityState === "hidden") return;

      setAvailabilityByIndex((prev) => {
        if (prev.length === 0) return prev;

        const next = [...prev];
        const randomIndex = Math.floor(Math.random() * next.length);
        next[randomIndex] = !next[randomIndex];
        return next;
      });
    }, 6000);

    return () => window.clearInterval(id);
  }, [isPaused, isInView]);

  useEffect(() => {
    const scroller = scrollerRef.current;
    if (!scroller) return;

    let raf = 0;

    const onScroll = () => {
      window.cancelAnimationFrame(raf);

      raf = window.requestAnimationFrame(() => {
        const current = scrollerRef.current;
        if (!current) return;

        // Determine which page-start card is closest to the scroller's left edge.
        let bestPage = 0;
        let bestDistance = Number.POSITIVE_INFINITY;

        for (let page = 0; page < pageCount; page++) {
          const startIndex = page * cardsPerPage;
          const el = current.children.item(startIndex) as HTMLElement | null;
          if (!el) continue;

          const distance = Math.abs(el.offsetLeft - current.scrollLeft);
          if (distance < bestDistance) {
            bestDistance = distance;
            bestPage = page;
          }
        }

        setActivePage((prev) => {
          if (prev === bestPage) return prev;
          skipNextScrollIntoViewRef.current = true;
          return bestPage;
        });
      });
    };

    scroller.addEventListener("scroll", onScroll, { passive: true });
    return () => {
      window.cancelAnimationFrame(raf);
      scroller.removeEventListener("scroll", onScroll);
    };
  }, [cardsPerPage, pageCount]);

  return (
    <section className="py-24 px-6 bg-background">
      <div className="max-w-7xl mx-auto">
        {/* Section Header */}
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold tracking-tight">
            Featured Freelancers
          </h2>

          <p className="text-muted-foreground mt-4 max-w-xl mx-auto">
            Discover top Nigerian professionals ready to help you build, grow,
            and scale your business.
          </p>
        </div>

        {/* Freelancer Carousel */}
        {loading && (
          <div className="flex justify-center py-16 text-muted-foreground text-sm">
            Loading freelancers…
          </div>
        )}
        {!loading && freelancers.length === 0 && (
          <div className="flex justify-center py-16 text-muted-foreground text-sm">
            No freelancers available yet.
          </div>
        )}
        {!loading && freelancers.length > 0 && (
          <div
            ref={carouselRef}
            className="relative"
            onMouseEnter={() => setIsPaused(true)}
            onMouseLeave={() => setIsPaused(false)}
            onPointerDown={() => setIsPaused(true)}
            onPointerUp={() => setIsPaused(false)}
            onPointerCancel={() => setIsPaused(false)}
          >
            <div
              ref={scrollerRef}
              className="-mx-6 px-6 flex gap-6 overflow-x-auto scroll-smooth snap-x snap-mandatory pb-3"
              aria-label="Featured freelancers"
            >
              {freelancers.map((freelancer, index) => (
                <div
                  key={freelancer.id}
                  className="snap-start shrink-0 w-full md:w-[calc((100%-24px)/2)] lg:w-[calc((100%-72px)/4)] py-8
                  "
                >
                  <div className="group relative border rounded-2xl p-6 hover:shadow-xl transition bg-card h-full">
                    {/* Top Rated badge for featured freelancers */}
                    {freelancer.featured && (
                      <div className="absolute top-0  my-2 left-4 z-10 inline-flex items-center gap-1 rounded-full bg-linear-to-r from-yellow-500 to-amber-400 text-white text-[10px] font-bold px-3 py-1 shadow-md shadow-yellow-400/30">
                        <Crown className="w-3 h-3" />
                        Top Rated
                      </div>
                    )}

                    {/* Live Availability */}
                    {(() => {
                      const isAvailable = availabilityByIndex[index] ?? false;

                      return (
                        <span
                          className={
                            "absolute right-4 top-2 inline-flex items-center gap-2 rounded-full border px-3 py-1 text-xs font-medium " +
                            (isAvailable
                              ? "border-primary/30 bg-primary/10 text-primary"
                              : "border-muted bg-muted text-foreground")
                          }
                          aria-label={
                            isAvailable ? "Available now" : "Currently busy"
                          }
                        >
                          <span
                            className={
                              "h-2 w-2 rounded-full " +
                              (isAvailable
                                ? "bg-primary"
                                : "bg-muted-foreground/60")
                            }
                          />
                          {isAvailable ? "Available now" : "Busy"}
                        </span>
                      );
                    })()}

                    {/* Profile */}
                    <div className="flex items-center gap-4 mb-4 mt-3">
                      {freelancer.image ? (
                        <Image
                          src={freelancer.image}
                          alt={freelancer.name}
                          width={60}
                          height={60}
                          className="rounded-full object-cover shrink-0"
                        />
                      ) : (
                        <div className="w-15 h-15 rounded-full bg-primary/10 flex items-center justify-center shrink-0 text-primary font-bold text-lg">
                          {getInitials(freelancer.name)}
                        </div>
                      )}

                      <div>
                        <h3 className="font-semibold">{freelancer.name}</h3>

                        <p className="text-sm text-muted-foreground">
                          {freelancer.role}
                        </p>
                      </div>
                    </div>

                    {/* Skills */}
                    <div className="flex flex-wrap gap-2 mb-6">
                      {freelancer.skills.slice(0, 3).map((skill, i) => (
                        <span
                          key={i}
                          className="text-xs bg-muted px-3 py-1 rounded-full"
                        >
                          {skill}
                        </span>
                      ))}
                    </div>

                    {/* Price + CTA */}
                    <div className="flex items-center justify-between">
                      <span className="font-semibold text-primary">
                        {freelancer.price}
                      </span>

                      <Link
                        href={`/freelancer/${freelancer.id}`}
                        className="text-sm font-medium hover:underline"
                      >
                        View
                      </Link>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            {/* Pagination */}
            {pageCount > 1 && (
              <div
                className="mt-6 flex items-center justify-center gap-2"
                aria-label="Carousel pagination"
              >
                {Array.from({ length: pageCount }).map((_, page) => {
                  const isActive = page === activePage;

                  return (
                    <button
                      key={page}
                      type="button"
                      onClick={() => setActivePage(page)}
                      className={
                        "h-6 min-w-6 rounded-full transition-all flex items-center justify-center " +
                        (isActive ? "w-8" : "w-6")
                      }
                      aria-label={`Go to page ${page + 1}`}
                      aria-current={isActive ? "true" : "false"}
                    >
                      <span
                        className={
                          "h-2.5 rounded-full transition-all " +
                          (isActive ? "w-8 bg-primary" : "w-2.5 bg-muted")
                        }
                      />
                    </button>
                  );
                })}
              </div>
            )}
          </div>
        )}
        {/* Browse Button */}
        <div className="text-center mt-16">
          <Link
            href="/browse-talents"
            className="inline-flex items-center px-6 py-3 rounded-lg bg-primary text-primary-foreground font-medium hover:opacity-90 transition"
          >
            Browse All Freelancers
          </Link>
        </div>
      </div>
    </section>
  );
}

"use client";

import {
  Code2,
  Palette,
  PenTool,
  Megaphone,
  BarChart3,
  Headphones,
} from "lucide-react";

import Link from "next/link";
import { useEffect, useMemo, useState } from "react";

import { Button } from "@/components/ui/button";
import { Feature } from "@/components/ui/feature-section-with-bento-grid";

const services = [
  {
    title: "Web Development",
    description:
      "Hire experienced developers to build websites, web apps, and e-commerce platforms.",
    icon: Code2,
  },
  {
    title: "UI/UX Design",
    description:
      "Professional designers creating beautiful and user-friendly product experiences.",
    icon: Palette,
  },
  {
    title: "Content Writing",
    description:
      "High-quality blog posts, website copy, and SEO content for your business.",
    icon: PenTool,
  },
  {
    title: "Digital Marketing",
    description:
      "Grow your business with SEO, paid ads, and social media marketing.",
    icon: Megaphone,
  },
  {
    title: "Data & Analytics",
    description:
      "Turn data into insights with dashboards, reports, and analysis.",
    icon: BarChart3,
  },
  {
    title: "Virtual Assistance",
    description:
      "Reliable assistants to handle admin tasks and business operations.",
    icon: Headphones,
  },
];

export default function Services() {
  const [itemsPerPage, setItemsPerPage] = useState(services.length);
  const [page, setPage] = useState(0);

  useEffect(() => {
    const updateItemsPerPage = () => {
      const width = window.innerWidth;

      if (width >= 1024) return setItemsPerPage(services.length);
      if (width >= 768) return setItemsPerPage(4);
      return setItemsPerPage(2);
    };

    updateItemsPerPage();
    window.addEventListener("resize", updateItemsPerPage);
    return () => window.removeEventListener("resize", updateItemsPerPage);
  }, []);

  const pageCount = useMemo(() => {
    return Math.max(1, Math.ceil(services.length / itemsPerPage));
  }, [itemsPerPage]);

  const currentPage = Math.min(page, pageCount - 1);

  const pagedServices = useMemo(() => {
    const start = currentPage * itemsPerPage;
    return services.slice(start, start + itemsPerPage);
  }, [currentPage, itemsPerPage]);

  useEffect(() => {
    if (page !== currentPage) setPage(currentPage);
  }, [page, currentPage]);

  return (
    <section className="py-24 px-6 bg-muted/40">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold tracking-tight">
            Services You Can Hire
          </h2>

          <p className="text-muted-foreground mt-4 max-w-xl mx-auto">
            Find skilled Nigerian professionals ready to deliver high-quality
            services for your business.
          </p>
        </div>

        {/* Desktop: Bento Grid */}
        <div className="hidden lg:block">
          <Feature
            variant="embedded"
            showHeader={false}
            items={services.map((service) => ({
              title: service.title,
              description: service.description,
              icon: service.icon,
            }))}
          />
        </div>

        {/* Mobile/Tablet: Paginated Grid */}
        <div className="lg:hidden">
          <div className="grid gap-8 md:grid-cols-2 lg:grid-cols-3">
            {pagedServices.map((service, index) => {
              const Icon = service.icon;

              return (
                <div
                  key={`${service.title}-${index}`}
                  className="group rounded-2xl border bg-card p-8 hover:shadow-xl transition"
                >
                  {/* Icon */}
                  <div className="w-12 h-12 flex items-center justify-center rounded-lg bg-primary/10 mb-6">
                    <Icon className="w-6 h-6 text-primary" />
                  </div>

                  {/* Title */}
                  <h3 className="text-xl font-semibold mb-3">
                    {service.title}
                  </h3>

                  {/* Description */}
                  <p className="text-muted-foreground text-sm leading-relaxed mb-6">
                    {service.description}
                  </p>

                  {/* Link */}
                  <Link
                    href="/services"
                    className="text-sm font-medium text-primary group-hover:underline"
                  >
                    Explore service →
                  </Link>
                </div>
              );
            })}
          </div>

          {/* Pagination */}
          {pageCount > 1 && (
            <div className="mt-10 flex items-center justify-center gap-3">
              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={() => setPage((p) => Math.max(0, p - 1))}
                disabled={currentPage === 0}
                aria-label="Previous page"
              >
                Prev
              </Button>

              <div
                className="flex items-center gap-2"
                aria-label="Service pagination"
              >
                {Array.from({ length: pageCount }).map((_, p) => {
                  const isActive = p === currentPage;

                  return (
                    <button
                      key={p}
                      type="button"
                      onClick={() => setPage(p)}
                      className={
                        "h-2.5 rounded-full transition-all " +
                        (isActive ? "w-8 bg-primary" : "w-2.5 bg-muted")
                      }
                      aria-label={`Go to page ${p + 1}`}
                      aria-current={isActive ? "true" : "false"}
                    />
                  );
                })}
              </div>

              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={() => setPage((p) => Math.min(pageCount - 1, p + 1))}
                disabled={currentPage === pageCount - 1}
                aria-label="Next page"
              >
                Next
              </Button>
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

